import{_ as n,o as l,c as i,a3 as s,j as e,a as r,t as a}from"./chunks/framework.DACwFHq9.js";const S=JSON.parse('{"title":"AIO Hub 设置架构总集篇","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/settings-architecture-overview.md","filePath":"architecture/settings-architecture-overview.md","lastUpdated":1784122179000}'),g={name:"architecture/settings-architecture-overview.md"};function d(o,t,c,u,h,p){return l(),i("div",null,[t[7]||(t[7]=s('<h1 id="aio-hub-设置架构总集篇" tabindex="-1">AIO Hub 设置架构总集篇 <a class="header-anchor" href="#aio-hub-设置架构总集篇" aria-label="Permalink to &quot;AIO Hub 设置架构总集篇&quot;">​</a></h1><blockquote><p>本文档是 <code>src/views/Settings/</code> 下目前已实现的 <strong>13 个设置模块</strong> 的架构速览，按注册顺序排列。 每个条目概述核心定位、关键配置项与交互亮点。</p></blockquote><hr><h2 id="一、核心运行时设置" tabindex="-1">一、核心运行时设置 <a class="header-anchor" href="#一、核心运行时设置" aria-label="Permalink to &quot;一、核心运行时设置&quot;">​</a></h2><h3 id="_1-general-—-通用设置" tabindex="-1">1. general — 通用设置 <a class="header-anchor" href="#_1-general-—-通用设置" aria-label="Permalink to &quot;1. general — 通用设置&quot;">​</a></h3><p>应用的<strong>核心运行时配置面板</strong>，涵盖窗口行为、主题、网络代理、时区、下载管理等基础功能。</p><ul><li><strong>配置管理</strong>: 打开配置目录、导出配置至 ZIP、导入配置（支持合并/覆盖两种模式）。</li><li><strong>窗口与托盘</strong>: 显示/隐藏托盘图标、关闭到托盘（依赖托盘图标启用）。</li><li><strong>主题与外观</strong>: 跟随系统/浅色/深色模式切换。</li><li><strong>侧边栏模式</strong>: 默认/抽屉/下拉菜单三种布局。</li><li><strong>窗口位置记忆</strong>: 清除已保存的窗口位置和大小状态。</li><li><strong>自动调整窗口位置</strong>: 工具窗口移出屏幕时自动拉回可见区域。</li><li><strong>系统时区</strong>: 支持跟随系统或手动选择时区（基于 <code>Intl.supportedValuesOf(&quot;timeZone&quot;)</code>）。</li><li><strong>网络代理</strong>: 跟随系统/不使用代理/自定义代理（支持自定义代理 URL）。</li><li><strong>下载设置</strong>: 默认下载路径、总是询问保存位置、下载完成通知、标题栏下载按钮。</li></ul><p><strong>亮点</strong>: 配置导入导出的 ZIP 打包机制、托盘图标动态创建/移除（Rust 后端实时同步）、响应式时区列表。</p><hr><h3 id="_2-startup-—-启动项管理" tabindex="-1">2. startup — 启动项管理 <a class="header-anchor" href="#_2-startup-—-启动项管理" aria-label="Permalink to &quot;2. startup — 启动项管理&quot;">​</a></h3><p><strong>自启动任务管理器</strong>，管理工具模块的异步并行启动行为，内置<strong>熔断机制</strong>。</p><ul><li><strong>启动项列表</strong>: 自动发现实现了 <code>startupConfig</code> 的工具模块。</li><li><strong>启停控制</strong>: 每个启动项独立开关，支持手动启用/禁用。</li><li><strong>熔断保护</strong>: 连续多次失败自动禁用，保留 <code>consecutiveFailures</code> 计数和 <code>lastError</code> 信息。</li><li><strong>执行状态展示</strong>: 显示上次启动结果（成功/失败）及耗时。</li><li><strong>统计信息</strong>: 由 <code>startupManager</code> 统一管理执行结果，<code>toolRegistryManager</code> 提供启动项注册。</li></ul><p><strong>亮点</strong>: 熔断机制防止故障扩散、异步并行执行、执行耗时/状态可视化。</p><hr><h2 id="二、主题与外观系统" tabindex="-1">二、主题与外观系统 <a class="header-anchor" href="#二、主题与外观系统" aria-label="Permalink to &quot;二、主题与外观系统&quot;">​</a></h2><h3 id="_3-theme-colors-—-主题色配置" tabindex="-1">3. theme-colors — 主题色配置 <a class="header-anchor" href="#_3-theme-colors-—-主题色配置" aria-label="Permalink to &quot;3. theme-colors — 主题色配置&quot;">​</a></h3><p><strong>五色主题定制面板</strong>，支持预设色板和自定义颜色输入。</p><ul><li><strong>五种颜色类型</strong>: 主题色、成功色、警告色、危险色、信息色。</li><li><strong>预设色板</strong>: 每种颜色类型独立预设（17 种主题色预设、11 种成功色、14 种警告色等），包含 Element 标准色和 VOCALOID/UTAU 风格色。</li><li><strong>自定义颜色</strong>: 原生 <code>&lt;input type=&quot;color&quot;&gt;</code> 拾色器 + HEX 输入框，支持预览和应用。</li><li><strong>重置</strong>: 每种颜色一键恢复默认值。</li><li><strong>壁纸主题色联动</strong>: 当开启壁纸颜色提取时，主题色自动使用提取色并显示&quot;壁纸提取中&quot;标签。</li></ul><p><strong>亮点</strong>: 细粒度颜色分类、预设色板文化特色（VOCALOID 角色色系）、壁纸提取色自动覆盖。</p><hr><h3 id="_4-theme-appearance-—-主题壁纸外观" tabindex="-1">4. theme-appearance — 主题壁纸外观 <a class="header-anchor" href="#_4-theme-appearance-—-主题壁纸外观" aria-label="Permalink to &quot;4. theme-appearance — 主题壁纸外观&quot;">​</a></h3><p><strong>应用整体视觉质感控制中心</strong>，双栏布局：壁纸管理 + UI/窗口特效。</p><p><strong>壁纸管理（左栏）</strong>:</p><ul><li><strong>壁纸开关</strong>: 全局开关。</li><li><strong>壁纸模式</strong>: 静态壁纸 / 轮播模式（支持间隔、随机/顺序播放、暂停/继续、缩略图预览）。</li><li><strong>壁纸来源</strong>: 内置壁纸（网格选择）/ 自定义（文件选择、目录选择）。</li><li><strong>填充模式</strong>: Cover / Contain / 拉伸 / 平铺。</li><li><strong>拼贴选项</strong>: 缩放、旋转、水平/垂直翻转（仅 tile 模式）。</li></ul><p><strong>界面质感（右栏上半）</strong>:</p><ul><li><strong>UI 特效开关</strong>: 全局控制 UI 透明度与模糊。</li><li><strong>基础不透明度 / 分离窗口不透明度</strong>。</li><li><strong>背景色叠加</strong>: 开关、叠加颜色（支持屏幕吸色和壁纸自动提取）、混合模式（16 种 CSS blend modes）、叠加不透明度。</li><li><strong>主题色提取</strong>: 自动从壁纸提取主色调（四种策略：柔和/鲜艳/亮部/暗部）。</li><li><strong>壁纸不透明度</strong>。</li><li><strong>UI 模糊</strong>: 开关 + 强度控制。</li><li><strong>边线</strong>: 不透明度 + 宽度。</li><li><strong>代码块背景不透明度</strong>。</li></ul><p><strong>窗口特效（右栏下半 - 实验性）</strong>:</p><ul><li><strong>窗口背景特效</strong>: 无 / 模糊(Blur) / 亚克力(Acrylic) / 云母(Mica)。</li><li><strong>窗口背景不透明度</strong>: 独立开关 + 滑块。</li><li><strong>窗口阴影</strong>: 开关。</li><li><strong>Linux 检测</strong>: 自动禁用窗口特效并显示兼容性提示。</li></ul><p><strong>亮点</strong>: 壁纸轮播引擎、16 种背景色混合模式、主题色自动提取、EyeDropper API 取色、窗口原生特效控制（Blur/Acrylic/Mica）。</p><hr><h3 id="_5-css-override-—-css-样式覆盖" tabindex="-1">5. css-override — CSS 样式覆盖 <a class="header-anchor" href="#_5-css-override-—-css-样式覆盖" aria-label="Permalink to &quot;5. css-override — CSS 样式覆盖&quot;">​</a></h3><p><strong>全局 CSS 覆盖编辑系统</strong>，支持预设管理和代码编辑。</p><ul><li><strong>启用/禁用开关</strong>。</li><li><strong>预设管理</strong>: 内置预设 / 用户自定义预设 / 纯自定义模式。</li><li><strong>预设选择</strong>: 选中即进入预览模式（只读），&quot;应用选中的预设&quot;按钮写入生效。</li><li><strong>CSS 编辑器</strong>: 使用项目的富文本编辑器组件，自动保存（500ms 防抖）。</li><li><strong>状态指示器</strong>: 实时显示保存状态（未保存/保存中/已保存）。</li><li><strong>预设操作</strong>: 添加（基于当前内容）、删除、还原到预设基线。</li><li><strong>使用提示</strong>: 折叠面板内提供 CSS 覆盖最佳实践。</li></ul><p><strong>亮点</strong>: 预设-预览-应用三级操作流、@vueuse/core 响应式读写文件。</p><hr><h2 id="三、ai-服务配置" tabindex="-1">三、AI 服务配置 <a class="header-anchor" href="#三、ai-服务配置" aria-label="Permalink to &quot;三、AI 服务配置&quot;">​</a></h2><h3 id="_6-llm-service-—-llm-ai-服务配置" tabindex="-1">6. llm-service — LLM AI 服务配置 <a class="header-anchor" href="#_6-llm-service-—-llm-ai-服务配置" aria-label="Permalink to &quot;6. llm-service — LLM AI 服务配置&quot;">​</a></h3><p><strong>LLM 服务渠道管理器</strong>，支持多渠道 CRUD、模型管理与网络设置。</p><ul><li><strong>渠道管理</strong>: 侧边栏列表 + 编辑区布局，支持预设/空白创建，以及从 cURL、环境变量、JSON、TOML 粘贴或多文件批量导入；同时支持删除、启用/禁用、拖拽排序。</li><li><strong>配置导入</strong>: 纯 TypeScript 解析层统一生成一个或多个候选渠道，支持 Claude Code、Gemini CLI、Codex、Grok CLI、OpenCode，并对 Codex 配置/凭据文件执行保守配对。</li><li><strong>基本信息</strong>: 渠道名称、API 格式类型（基于 <code>providerTypes</code>）、供应商图标（预设图标选择器）、API 地址（支持快捷链接和端点预览）。</li><li><strong>渠道特有配置</strong>: 动态渲染 Provider 级配置字段（<code>SettingListRenderer</code>）。</li><li><strong>网络设置</strong>: 折叠面板，含网络方案（自动/后端代理/原生请求）、放宽证书校验、强制 HTTP/1.1、自定义请求头、高级端点。</li><li><strong>多密钥管理</strong>: 支持逗号分隔输入多个 API Key，弹窗管理密钥状态（启用/禁用），独立密钥测试。</li><li><strong>模型管理</strong>: 模型列表（分组展开）、新增/编辑/删除/批量删除模型组、模型获取（从 API 拉取）、模型连接测试。</li><li><strong>连接测试</strong>: 一键测试整个渠道连接、单模型测试、单密钥测试。</li></ul><p><strong>亮点</strong>: 多格式配置导入与候选预览、动态渠道特有配置、多密钥负载均衡、模型自动获取、自定义请求头/端点的细粒度网络控制。</p><hr><h3 id="_7-model-metadata-—-ai-模型元数据配置" tabindex="-1">7. model-metadata — AI 模型元数据配置 <a class="header-anchor" href="#_7-model-metadata-—-ai-模型元数据配置" aria-label="Permalink to &quot;7. model-metadata — AI 模型元数据配置&quot;">​</a></h3><p><strong>模型图标与分组元数据规则引擎</strong>，支持四种匹配类型和可视化管理。</p><ul><li><strong>规则引擎</strong>: 四种匹配类型（Provider / Model / Prefix / Group），支持正则表达式。</li><li><strong>可视化编辑</strong>: 网格/列表双视图，搜索过滤（关键字、启用状态）、排序（优先级/类型/名称/创建时间）、分页。</li><li><strong>CRUD 操作</strong>: 添加/编辑/删除/启用禁用规则。</li><li><strong>批量操作</strong>: 重置为默认、合并最新内置规则、导入/导出 JSON。</li><li><strong>测试模式</strong>: 输入模型 ID + Provider 实时调试匹配结果，显示匹配状态、命中规则、图标预览、候选规则列表。</li><li><strong>预设图标库</strong>: 预设图标选择对话框。</li></ul><p><strong>亮点</strong>: 实时测试模式调试匹配逻辑、正则和前缀多种匹配策略、内置规则合并更新机制。</p><hr><h3 id="_8-ocr-service-—-云端-ocr-服务" tabindex="-1">8. ocr-service — 云端 OCR 服务 <a class="header-anchor" href="#_8-ocr-service-—-云端-ocr-服务" aria-label="Permalink to &quot;8. ocr-service — 云端 OCR 服务&quot;">​</a></h3><p><strong>云端 OCR 服务渠道管理器</strong>，支持标准 OCR API 和自定义 API 请求配置。</p>',48)),e("ul",null,[t[3]||(t[3]=e("li",null,[e("strong",null,"渠道管理"),r(": 侧边栏列表 + 编辑区布局，支持创建（预设模板/空白）、删除、启用/禁用、拖拽排序。")],-1)),t[4]||(t[4]=e("li",null,[e("strong",null,"标准服务商配置"),r(": 服务名称、服务类型（百度云等预设 Provider）、API 端点、API Key、API Secret（百度云特有）。")],-1)),e("li",null,[t[0]||(t[0]=e("strong",null,"自定义服务支持",-1)),t[1]||(t[1]=r(": 自定义 API URL、HTTP 方法、请求头、请求体模板（支持 ",-1)),e("code",null,a(o.imageBase64),1),t[2]||(t[2]=r(" 变量）、结果提取路径。",-1))]),t[5]||(t[5]=e("li",null,[e("strong",null,"并发与限流"),r(": 并发数（1-10，控制图片块并行处理）、请求延迟（0-5000ms，避免限流）。")],-1)),t[6]||(t[6]=e("li",null,[e("strong",null,"自动保存"),r(": 1 秒防抖自动保存表单变更。")],-1))]),t[8]||(t[8]=s('<p><strong>亮点</strong>: 自定义 API 请求编辑器（无代码 OCR API 封装）、并发控制与限流保护、预设模板一键创建。</p><hr><h2 id="四、数据与用户配置" tabindex="-1">四、数据与用户配置 <a class="header-anchor" href="#四、数据与用户配置" aria-label="Permalink to &quot;四、数据与用户配置&quot;">​</a></h2><h3 id="_9-user-profiles-—-用户档案管理" tabindex="-1">9. user-profiles — 用户档案管理 <a class="header-anchor" href="#_9-user-profiles-—-用户档案管理" aria-label="Permalink to &quot;9. user-profiles — 用户档案管理&quot;">​</a></h3><p><strong>LLM 聊天用户档案管理</strong>，支持多档案 CRUD 和调用 <code>UserProfileForm</code> 进行编辑。</p><ul><li><strong>档案列表</strong>: 侧边栏列表（最近使用排序），显示头像、名称、描述截断、创建日期。</li><li><strong>档案编辑</strong>: 复用 <code>UserProfileForm</code> 组件，支持头像上传/清除、富文本样式行为配置、正则预置管理。</li><li><strong>创建档案</strong>: 弹窗交互，输入名称、显示名、简介、头像 URL。</li><li><strong>自动保存</strong>: 1 秒防抖自动保存表单变更。</li><li><strong>删除</strong>: 确认后删除包含配置文件的完整档案（回收站保护）。</li><li><strong>打开目录</strong>: 直接打开档案配置文件所在目录。</li></ul><p><strong>亮点</strong>: 与 LLM 聊天子系统深度集成、<code>UserProfileForm</code> 完整富文本样式支持、按需加载 <code>selectGlobalProfile</code>。</p><hr><h3 id="_10-asset-management-—-资产管理" tabindex="-1">10. asset-management — 资产管理 <a class="header-anchor" href="#_10-asset-management-—-资产管理" aria-label="Permalink to &quot;10. asset-management — 资产管理&quot;">​</a></h3><p><strong>资产存储路径配置</strong>，管理应用内所有文件类资产的存储位置。</p><ul><li><strong>默认路径</strong>: 显示应用数据目录下的 <code>assets</code> 文件夹路径（通过 Rust 后端获取）。</li><li><strong>自定义路径</strong>: 目录选择器，指定自定义存储位置。</li><li><strong>路径缓存刷新</strong>: 修改后自动清除 <code>useAssetManager</code> 中的路径缓存。</li><li><strong>重置</strong>: 一键恢复默认路径。</li><li><strong>说明</strong>: 资产分类存储机制、修改范围说明（仅新导入生效）。</li></ul><p><strong>亮点</strong>: Rust 后端获取路径、路径缓存自动失效、<code>convertFileSrc</code> 协议转换。</p><hr><h2 id="五、工具与日志管理" tabindex="-1">五、工具与日志管理 <a class="header-anchor" href="#五、工具与日志管理" aria-label="Permalink to &quot;五、工具与日志管理&quot;">​</a></h2><h3 id="_11-tools-—-工具模块" tabindex="-1">11. tools — 工具模块 <a class="header-anchor" href="#_11-tools-—-工具模块" aria-label="Permalink to &quot;11. tools — 工具模块&quot;">​</a></h3><p><strong>工具模块可见性与排序管理</strong>，拖拽排序 + 批量启停。</p><ul><li><strong>可见性控制</strong>: 每个工具独立勾选，批量全选/全不选。</li><li><strong>拖拽排序</strong>: 基于 <code>VueDraggableNext</code> 实现，拖拽时旋转动画，支持触摸设备。</li><li><strong>顺序持久化</strong>: 拖拽结束自动保存顺序到设置，同步更新 Store。</li><li><strong>重置顺序</strong>: 一键恢复默认工具顺序。</li><li><strong>统计</strong>: 实时显示已启用数/总数。</li></ul><p><strong>亮点</strong>: 拖拽排序 + 动画反馈、全选/全不选批量化操作、顺序与 Store 双向同步。</p><hr><h3 id="_12-log-settings-—-日志配置" tabindex="-1">12. log-settings — 日志配置 <a class="header-anchor" href="#_12-log-settings-—-日志配置" aria-label="Permalink to &quot;12. log-settings — 日志配置&quot;">​</a></h3><p><strong>应用日志系统控制面板</strong>，覆盖日志级别、输出、存储和统计。</p><ul><li><strong>日志级别</strong>: DEBUG / INFO / WARN / ERROR 可选，实时生效。</li><li><strong>输出控制</strong>: 文件日志开关、控制台日志开关。</li><li><strong>缓冲区配置</strong>: 内存缓冲区大小（500-50000 条）、单文件分割阈值（1MB-20MB）。</li><li><strong>日志统计</strong>: 实时显示各类别日志条数（总/DEBUG/INFO/WARN/ERROR）。</li><li><strong>日志操作</strong>: 打开日志目录（强制绕过前端 Scope）、导出日志为 TXT、清空内存缓冲区、生成测试日志。</li><li><strong>当前日志文件</strong>: 显示当日日志文件的完整路径。</li></ul><p><strong>亮点</strong>: 日志设置实时生效（<code>setLevel</code>/<code>setMaxFileSize</code> 等方法直接操作 Logger 实例）、日志统计面板、Rust 后端强制打开路径。</p><hr><h3 id="_13-about-—-关于" tabindex="-1">13. about — 关于 <a class="header-anchor" href="#_13-about-—-关于" aria-label="Permalink to &quot;13. about — 关于&quot;">​</a></h3><p><strong>应用信息与支持页面</strong>，展示版本信息和项目生态。</p><ul><li><strong>应用信息</strong>: 名称、版本（来自 Tauri API）、图标、简介。</li><li><strong>检查更新</strong>: 优先调用 Tauri updater 插件检查可安装更新，未配置或检查失败时回退 GitHub Releases API。</li><li><strong>应用内更新</strong>: 支持通过 updater 下载、安装并重启；发布公钥与更新清单接入前保留手动下载兜底。</li><li><strong>更新弹窗</strong>: 使用 <code>RichTextRenderer</code> 渲染 Release Notes，并展示下载 / 安装进度。</li><li><strong>项目链接</strong>: 开发者信息、仓库地址、许可证。</li><li><strong>支持项目</strong>: GitHub Star（外链）、爱发电赞助（高亮卡片）。</li><li><strong>版权信息</strong>: 页脚展示。</li></ul><p><strong>亮点</strong>: Tauri updater 应用内安装、GitHub Releases 兜底、RichTextRenderer 渲染更新日志、Alt+点击强制检测机制。</p><hr><h2 id="附录-设置模块索引" tabindex="-1">附录：设置模块索引 <a class="header-anchor" href="#附录-设置模块索引" aria-label="Permalink to &quot;附录：设置模块索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">序号</th><th>模块</th><th>路径</th><th>核心定位</th><th style="text-align:center;">关键配置项数</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td>general</td><td><a href="./../src/views/Settings/general/GeneralSettings.vue"><code>src/views/Settings/general/GeneralSettings.vue</code></a></td><td>通用运行时设置</td><td style="text-align:center;">15+</td></tr><tr><td style="text-align:center;">2</td><td>startup</td><td><a href="./../src/views/Settings/general/StartupSettings.vue"><code>src/views/Settings/general/StartupSettings.vue</code></a></td><td>自启动任务管理</td><td style="text-align:center;">N/A</td></tr><tr><td style="text-align:center;">3</td><td>theme-colors</td><td><a href="./../src/views/Settings/general/ThemeColorSettings.vue"><code>src/views/Settings/general/ThemeColorSettings.vue</code></a></td><td>五色主题定制</td><td style="text-align:center;">5</td></tr><tr><td style="text-align:center;">4</td><td>theme-appearance</td><td><a href="./../src/views/Settings/general/ThemeAppearanceSettings.vue"><code>src/views/Settings/general/ThemeAppearanceSettings.vue</code></a></td><td>壁纸外观+窗口特效</td><td style="text-align:center;">30+</td></tr><tr><td style="text-align:center;">5</td><td>css-override</td><td><a href="./../src/views/Settings/css/CssOverrideSettings.vue"><code>src/views/Settings/css/CssOverrideSettings.vue</code></a></td><td>CSS 样式覆盖编辑器</td><td style="text-align:center;">N/A(预设)</td></tr><tr><td style="text-align:center;">6</td><td>llm-service</td><td><a href="./../src/views/Settings/llm-service/LlmServiceSettings.vue"><code>src/views/Settings/llm-service/LlmServiceSettings.vue</code></a></td><td>LLM 服务渠道配置</td><td style="text-align:center;">4+</td></tr><tr><td style="text-align:center;">7</td><td>model-metadata</td><td><a href="./../src/views/Settings/model-metadata/ModelMetadataSettings.vue"><code>src/views/Settings/model-metadata/ModelMetadataSettings.vue</code></a></td><td>模型图标元数据规则引擎</td><td style="text-align:center;">N/A(规则)</td></tr><tr><td style="text-align:center;">8</td><td>ocr-service</td><td><a href="./../src/views/Settings/ocr-service/OcrServiceSettings.vue"><code>src/views/Settings/ocr-service/OcrServiceSettings.vue</code></a></td><td>云端 OCR 服务渠道配置</td><td style="text-align:center;">4+</td></tr><tr><td style="text-align:center;">9</td><td>user-profiles</td><td><a href="./../src/views/Settings/user-profile/UserProfileSettings.vue"><code>src/views/Settings/user-profile/UserProfileSettings.vue</code></a></td><td>用户档案管理</td><td style="text-align:center;">N/A(档案)</td></tr><tr><td style="text-align:center;">10</td><td>asset-management</td><td><a href="./../src/views/Settings/general/AssetSettings.vue"><code>src/views/Settings/general/AssetSettings.vue</code></a></td><td>资产管理路径配置</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">11</td><td>tools</td><td><a href="./../src/views/Settings/general/ToolsSettings.vue"><code>src/views/Settings/general/ToolsSettings.vue</code></a></td><td>工具模块可见性与排序</td><td style="text-align:center;">N/A</td></tr><tr><td style="text-align:center;">12</td><td>log-settings</td><td><a href="./../src/views/Settings/general/LogSettings.vue"><code>src/views/Settings/general/LogSettings.vue</code></a></td><td>日志系统控制面板</td><td style="text-align:center;">5</td></tr><tr><td style="text-align:center;">13</td><td>about</td><td><a href="./../src/views/Settings/about/AboutSettings.vue"><code>src/views/Settings/about/AboutSettings.vue</code></a></td><td>应用信息与支持</td><td style="text-align:center;">N/A</td></tr></tbody></table><hr><blockquote><p>📅 生成时间: 2026-05-07 📁 文档来源: <code>src/views/Settings/*/*.vue</code>（13 个设置模块源码汇总） 📐 布局架构: <code>src/views/Settings.vue</code>（骨架屏 + 导航联动 + 动态组件渲染） + <code>src/config/settings.ts</code>（模块注册）</p></blockquote>',33))])}const m=n(g,[["render",d]]);export{S as __pageData,m as default};
